**Overview:**

In this approach, we simulate the walk through the permutation using an iterative method. We maintain an array called `visited` to mark the indices that have already been processed. For every index iii from 111 to NNN, if it is not visited, we start traversing from iii. We repeatedly move to the position indicated by the current number until we come back to the starting index. Finally, we store the cycle (repeating the first index to signify closure) and continue with the next unvisited index.

**Why It Works:**


**Correctness:** Since every position points to exactly one other position (a property of permutations), starting at any unvisited position and following the chain will eventually lead back to the starting position.
**Efficiency:** The algorithm runs in O(N)O(N)O(N) time, as each index is visited exactly once.
**Code Implementations:**

Below is the C++ and Python implementation for the iterative approach.

`#include &lt;iostream&gt;
#include &lt;vector&gt;
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N;
    cin &gt;&gt; N;
    vector&lt;int&gt; perm(N + 1);
    for (int i = 1; i &lt;= N; i++) {
        cin &gt;&gt; perm[i];
    }

    vector&lt;bool&gt; visited(N + 1, false);
    vector&lt;vector&lt;int&gt;&gt; cycles;

    for (int i = 1; i &lt;= N; i++) {
        if (!visited[i]) {
            vector&lt;int&gt; cycle;
            int current = i;
            while (true) {
                cycle.push_back(current);
                visited[current] = true;
                int next = perm[current];
                if (visited[next])
                    break;
                current = next;
            }
            // Append the starting element to complete the cycle.
            cycle.push_back(cycle[0]);
            cycles.push_back(cycle);
        }
    }

    cout &lt;&lt; cycles.size() &lt;&lt; "\n";
    for (auto &amp;cycle : cycles) {
        for (int x : cycle) {
            cout &lt;&lt; x &lt;&lt; " ";
        }
        cout &lt;&lt; "\n";
    }
    return 0;
}
``def main():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    n = int(data[0])
    perm = [0] * (n + 1)
    for i in range(n):
        perm[i + 1] = int(data[i + 1])

    visited = [False] * (n + 1)
    cycles = []

    for i in range(1, n + 1):
        if not visited[i]:
            cycle = []
            current = i
            while True:
                cycle.append(current)
                visited[current] = True
                next_num = perm[current]
                if visited[next_num]:
                    break
                current = next_num
            # Append starting element to complete the cycle.
            cycle.append(cycle[0])
            cycles.append(cycle)

    output_lines = [str(len(cycles))]
    for cycle in cycles:
        output_lines.append(" ".join(map(str, cycle)))
    sys.stdout.write("\n".join(output_lines))

if __name__ == "__main__":
    main()
`**Overview:**

In this approach, we interpret the permutation as a directed graph where each node (position) has an edge to the node given by the value at that position. We then use recursive DFS to traverse the graph starting from an unvisited node until we circle back to the start. This recursion naturally records the cycle as it unwinds.

**Why It Works:**


**Clarity:** The recursive approach elegantly captures the notion of traversing a path until a cycle is detected.
**Similarity:** Although similar to the iterative simulation, recursion can sometimes lead to simpler and more readable code for beginners.
**Code Implementations:**

Below is the C++ and Python implementation for the recursive DFS approach.

`#include &lt;iostream&gt;
#include &lt;vector&gt;
using namespace std;

void dfs(int current, int start, const vector&lt;int&gt;&amp; perm, vector&lt;bool&gt;&amp; visited, vector&lt;int&gt;&amp; cycle) {
    cycle.push_back(current);
    visited[current] = true;
    int next = perm[current];
    if (next == start) {
        cycle.push_back(start);
        return;
    }
    if (!visited[next]) {
        dfs(next, start, perm, visited, cycle);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin &gt;&gt; N;
    vector&lt;int&gt; perm(N + 1);
    for (int i = 1; i &lt;= N; i++) {
        cin &gt;&gt; perm[i];
    }

    vector&lt;bool&gt; visited(N + 1, false);
    vector&lt;vector&lt;int&gt;&gt; cycles;

    for (int i = 1; i &lt;= N; i++) {
        if (!visited[i]) {
            vector&lt;int&gt; cycle;
            dfs(i, i, perm, visited, cycle);
            cycles.push_back(cycle);
        }
    }

    cout &lt;&lt; cycles.size() &lt;&lt; "\n";
    for (auto &amp;cycle : cycles) {
        for (int x : cycle) {
            cout &lt;&lt; x &lt;&lt; " ";
        }
        cout &lt;&lt; "\n";
    }
    return 0;
}
``def dfs(current, start, perm, visited, cycle):
    cycle.append(current)
    visited[current] = True
    next_node = perm[current]
    if next_node == start:
        cycle.append(start)
        return
    if not visited[next_node]:
        dfs(next_node, start, perm, visited, cycle)

def main():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    n = int(data[0])
    perm = [0] * (n + 1)
    for i in range(n):
        perm[i + 1] = int(data[i + 1])

    visited = [False] * (n + 1)
    cycles = []

    for i in range(1, n + 1):
        if not visited[i]:
            cycle = []
            dfs(i, i, perm, visited, cycle)
            cycles.append(cycle)

    output_lines = [str(len(cycles))]
    for cycle in cycles:
        output_lines.append(" ".join(map(str, cycle)))
    sys.stdout.write("\n".join(output_lines))

if __name__ == "__main__":
    main()
